public class FibFib {
    public static void main(String[] args) {
        System.out.println(fibfib(1)); // Output: 0
        System.out.println(fibfib(5)); // Output: 4
        System.out.println(fibfib(8)); // Output: 24
    }

    public static int fibfib(int n) {
        if (n == 0 || n == 1) {
            return 0;
        } else if (n == 2) {
            return 1;
        }

        int[] fibfibValues = new int[n + 1];
        fibfibValues[0] = 0;
        fibfibValues[1] = 0;
        fibfibValues[2] = 1;

        for (int i = 3; i <= n; i++) {
            fibfibValues[i] = fibfibValues[i - 1] + fibfibValues[i - 2] + fibfibValues[i - 3];
        }

        return fibfibValues[n];
    }
}
