public class ChaosSorcerer {
    public static void main(String[] args) {
        // Example usage
        String[] strings = {"hello", "world", "java"};
        int totalLength = dissolve(strings);
        System.out.println(totalLength);
    }

    public static int dissolve(String[] strings) {
        int totalLength = 0;
        for (String str : strings) {
            totalLength += str.length();
        }
        return totalLength;
    }
}
